const {BigQuery} = require('@google-cloud/bigquery');

exports.aggregateBigQueryData = async (req, res) => {
  const bigquery = new BigQuery();

  const projectId = process.env.GOOGLE_CLOUD_PROJECT || 'your-gcp-project-id'; // Replace with your GCP Project ID
  const datasetId = 'your_dataset_id'; // Replace with your BigQuery Dataset ID
  const tableId = 'your_table_id';   // Replace with your BigQuery Table ID

  const query = `
    SELECT
      field_to_group_by,
      COUNT(*) as record_count,
      SUM(numeric_field) as total_numeric_value,
      AVG(numeric_field) as average_numeric_value
    FROM
      \`${projectId}.${datasetId}.${tableId}\`
    WHERE
      -- Example condition: process data from the last 30 days
      event_timestamp >= TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 30 DAY)
    GROUP BY
      field_to_group_by
    ORDER BY
      record_count DESC
    LIMIT 10000; -- Adjust limit based on expected aggregated result size and memory
  `;

  const options = {
    query: query,
    location: 'US', // Specify the BigQuery dataset location (e.g., 'US', 'EU', 'asia-east1')
    maxResults: 500000 // Max number of rows to retrieve from the aggregated result (ensure it fits in 8GB memory)
  };

  try {
    const [job] = await bigquery.createQueryJob(options);
    console.log(`BigQuery Job ${job.id} started.`);

    const [rows] = await job.getQueryResults();

    console.log(`BigQuery Job ${job.id} finished. Found ${rows.length} aggregated rows.`);

    res.status(200).json({
      status: 'success',
      message: 'BigQuery data aggregated successfully.',
      aggregatedData: rows,
      rowCount: rows.length
    });

  } catch (error) {
    console.error('ERROR during BigQuery aggregation:', error);
    res.status(500).json({
      status: 'error',
      message: 'Failed to aggregate data from BigQuery.',
      details: error.message
    });
  }
};
